export interface DashboardWidgetData {
  id: number;
  titleJson: MultilingualText;
  icon: string;
  color: string;
  gridW: number;
  gridH: number;
  sortOrder: number;
  /** @nullable */
  widgetType?: DashboardWidgetDataWidgetType;
  /** @nullable */
  chartType?: string | null;
  /**
     * When true, the chart widget renders numeric value labels directly on the chart
     * @nullable
     */
  showValues?: boolean | null;
  /** Grouped buckets for chart widgets (admin-authoritative real totals) */
  series?: ChartSeriesPoint[];
  /** Column metadata for table widgets, in display order */
  tableColumns?: TableColumn[];
  /** Rows for table widgets (admin-authoritative, status-filtered, limited) */
  tableRows?: TableRow[];
  /**
     * For table widgets, the source entity id (lets the client link rows to the entity's page)
     * @nullable
     */
  tableEntityId?: number | null;
  /** @nullable */
  formula?: string | null;
  /** @nullable */
  format?: string | null;
  /** @nullable */
  colorStyle?: DashboardWidgetDataColorStyle;
  /** @nullable */
  textColor?: DashboardWidgetDataTextColor;
  /** Computed value per metric key (admin-authoritative real totals) */
  metrics: DashboardWidgetDataMetrics;
  notes?: NotesData;
  /**
     * For notes widgets, whether the requesting viewer may inline-edit this widget's content (page-admin or a role in editableRoleIds).
     * @nullable
     */
  canEditNotes?: boolean | null;
}

