export type FieldType = typeof FieldType[keyof typeof FieldType];


export const FieldType = {
  text: 'text',
  textarea: 'textarea',
  number: 'number',
  boolean: 'boolean',
  date: 'date',
  datetime: 'datetime',
  select: 'select',
  email: 'email',
  url: 'url',
  phone: 'phone',
  user: 'user',
  file: 'file',
  function: 'function',
  relation: 'relation',
} as const;

export type FormatOperator = typeof FormatOperator[keyof typeof FormatOperator];


export const FormatOperator = {
  equals: 'equals',
  notEquals: 'notEquals',
  contains: 'contains',
  notContains: 'notContains',
  empty: 'empty',
  notEmpty: 'notEmpty',
  gt: 'gt',
  lt: 'lt',
  gte: 'gte',
  lte: 'lte',
} as const;

/**
 * One conditional-formatting rule. When a cell value matches operator/value, the cell is painted cellColor and/or the row rowColor, and the cell text is painted textColor. Rules are evaluated in order; first match wins per field.
 */
export interface FieldFormatRule {
  operator: FormatOperator;
  value?: string;
  cellColor?: string;
  rowColor?: string;
  textColor?: string;
}

/**
 * Per-field configuration for a `function`-type field. `expression` is a safe formula referencing other fields of the same record via {field_key}; it is computed at read time and never stored.
 */
export interface FormulaFieldConfig {
  expression?: string;
}

/**
 * Per-field configuration for a dependent ("cascading") field. When `dependsOnFieldKey` is set, this field is gated on the parent field: its picker is disabled until the parent has a value, and its option list is the distinct existing values of this field among records whose parent-chain matches the current row.
 */
export interface DependencyFieldConfig {
  dependsOnFieldKey?: string;
}

export type FieldAccess = typeof FieldAccess[keyof typeof FieldAccess];


export const FieldAccess = {
  hidden: 'hidden',
  view: 'view',
  edit: 'edit',
} as const;

export interface FieldPermissions {[key: string]: FieldAccess}

/**
 * A source a file-type field value may come from.
 */
export type FileSource = typeof FileSource[keyof typeof FileSource];


export const FileSource = {
  server: 'server',
  gdrive: 'gdrive',
  link: 'link',
} as const;

/**
 * Per-field configuration for a `file`-type field. `allowedSources` lists which fill-time sources are offered/accepted. Empty or unset means the legacy default (server upload only).
 */
export interface FileFieldConfig {
  allowedSources?: FileSource[];
  /** Google Drive folder id this field's uploads land in (one of the admin-managed folders). Unset means the default upload folder. */
  driveFolderId?: string;
}

/**
 * Per-field configuration for a `user`-type field. `allowedRoleIds` restricts selectable users to those roles. Empty or unset means any user may be selected. `allowCreate` lets a user be created inline from the value picker, with the new account's role limited to `allowedRoleIds`.
 */
export interface UserFieldConfig {
  allowedRoleIds?: number[];
  allowCreate?: boolean;
}

